package com.corporativoalpha.bookingservice.controllers;import com.corporativoalpha.bookingservice.models.Booking;import com.corporativoalpha.bookingservice.services.BookingService;import org.springframework.http.HttpStatus;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.annotation.*;import java.util.List;import java.util.Map;@RestController@RequestMapping("/api")public class BookingController {private final BookingService bookingService;public BookingController(BookingService bookingService){this.bookingService=bookingService;}@PostMapping("/auth/login")public ResponseEntity<?> login(@RequestBody Map<String, String> credentials){String email=credentials.get("email");String password=credentials.get("password");if("admin@corporativoalpha.com".equals(email) && "Admin123".equals(password)){return ResponseEntity.ok(Map.of("token","mock-jwt-token-admin","role","ADMINISTRADOR","email",email));}else if(("carlos.mendez@corporativoalpha.com".equals(email) || "ana.torres@corporativoalpha.com".equals(email)) && "User123".equals(password)){return ResponseEntity.ok(Map.of("token","mock-jwt-token-colaborador","role","COLABORADOR","email",email));}return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body(Map.of("error","Credenciales invalidas"));}@PostMapping("/bookings")public ResponseEntity<?> createBooking(@RequestBody Booking booking){try{return ResponseEntity.status(HttpStatus.CREATED).body(bookingService.createBooking(booking));}catch(IllegalArgumentException e){return ResponseEntity.badRequest().body(Map.of("error",e.getMessage()));}catch(IllegalStateException e){return ResponseEntity.status(HttpStatus.CONFLICT).body(Map.of("error",e.getMessage()));}catch(RuntimeException e){return ResponseEntity.status(HttpStatus.NOT_FOUND).body(Map.of("error",e.getMessage()));}}@GetMapping("/bookings/my/{userId}")public List<Booking> getMyBookings(@PathVariable Long userId){return bookingService.getMyBookings(userId);}@DeleteMapping("/bookings/{id}")public ResponseEntity<Void> cancelBooking(@PathVariable Long id){try{bookingService.cancelBooking(id);return ResponseEntity.noContent().build();}catch(RuntimeException e){return ResponseEntity.notFound().build();}}}
